func accountBalanceColor(a store.Account) string {
	if isAccountNegativeBalance(a) {
		return "color:var(--commit)"
	}
	return "color:var(--text)"
}

func txSettlementStyle(status string) string {
	if status == "settled" {
		return "font-size:11px;padding:2px 6px;border-radius:4px;background:color-mix(in srgb,var(--surface2) 80%,var(--income) 20%);color:var(--income)"
	}
	return "font-size:11px;padding:2px 6px;border-radius:4px;background:var(--surface2);color:var(--text3)"
}

func uploadAccountJSON(a store.Account) string {
	type acc struct {
		ID                   string   `json:"id"`
		Name                 string   `json:"name"`
		AccountType          string   `json:"account_type"`
		Status               string   `json:"status"`
		InterestRate         *float64 `json:"interest_rate"`
		StartingBalanceCents int64    `json:"starting_balance_cents"`
		CreditLimitCents     *int64   `json:"credit_limit_cents"`
	}
	b, _ := json.Marshal(acc{
		ID: a.ID, Name: a.Name, AccountType: a.AccountType, Status: a.Status,
		InterestRate: a.InterestRate, StartingBalanceCents: a.StartingBalanceCents, CreditLimitCents: a.CreditLimitCents,
	})
	return string(b)
}

func uploadInstitutionJSON(inst *store.Institution) string {
	if inst == nil {
		return "null"
	}
	type instJSON struct {
		ID                   string          `json:"id"`
		InstitutionName      string          `json:"institution_name"`
		SourceType           string          `json:"source_type"`
		SettlementWindowDays int             `json:"settlement_window_days"`
		DedupWindowDays      int             `json:"dedup_window_days"`
		AmountTolerancePct   float64         `json:"amount_tolerance_pct"`
		MappingConfig        json.RawMessage `json:"mapping_config"`
	}
	b, _ := json.Marshal(instJSON{
		ID:                   inst.ID,
		InstitutionName:      inst.InstitutionName,
		SourceType:           inst.SourceType,
		SettlementWindowDays: inst.SettlementWindowDays,
		DedupWindowDays:      inst.DedupWindowDays,
		AmountTolerancePct:   inst.AmountTolerancePct,
		MappingConfig:        inst.MappingConfig,
	})
	return string(b)
}

